 35	int send_messages_txt(int s, char *T_messages_txt, int T_messages_txt_len)
 36	{
 37	  char buf[T_BUFFER_MAX];
 38	  char *T_LOCAL_buf = buf;
 39	  int32_t T_LOCAL_size;
 40	  unsigned char *src;
 41	  int src_len;
 42	
 43	  /* trace T_message.txt
 44	   * Send several messages -1 with content followed by message -2.
 45	   */
 46	  src = (unsigned char *)T_messages_txt;
 47	  src_len = T_messages_txt_len;
 48	  while (src_len) {
 49	    int send_size = src_len;
 50	    if (send_size > T_PAYLOAD_MAXSIZE - sizeof(int))
 51	      send_size = T_PAYLOAD_MAXSIZE - sizeof(int);
 52	    /* TODO: be careful, we use internal T stuff, to rewrite? */
 53	    T_LOCAL_size = 0;
 54	    T_HEADER(T_ID(-1));
 55	    T_PUT_buffer(1, ((T_buffer){.addr = src, .length = send_size}));
 56	    if (socket_send(s, &T_LOCAL_size, 4) == -1) return -1;
 57	    if (socket_send(s, buf, T_LOCAL_size) == -1) return -1;
 58	    src += send_size;
 59	    src_len -= send_size;
 60	  }
 61	  T_LOCAL_size = 0;
 62	  T_HEADER(T_ID(-2));
 63	  if (socket_send(s, &T_LOCAL_size, 4) == -1) return -1;
 64	  return socket_send(s, buf, T_LOCAL_size);
 65	}
